<div class="card"><div class="card-head"><h3>Contact Messages</h3></div><div class="table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Subject</th><th>Message</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach ($messages as $msg): ?><tr><td><?= e($msg['name']) ?></td><td><?= e($msg['email']) ?></td><td><?= e($msg['subject']) ?></td><td><?= e($msg['message']) ?></td><td><?= e($msg['status']) ?></td><td><?php if ($msg['status'] !== 'reviewed'): ?><form method="post" action="<?= base_url('index.php?route=admin/contact-messages/review') ?>" class="inline-form"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$msg['id'] ?>"><button class="btn btn-sm btn-outline">Mark Reviewed</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if (!$messages): ?><tr><td colspan="6">No contact messages yet.</td></tr><?php endif; ?></tbody></table></div></div>
